const MONO = '"Courier New", monospace';
const TAU = Math.PI * 2;

type Point = {x: number; y: number};
type GeoNode = Point & {id: string; tier: 'origin' | 'relay' | 'target'; phase: number};

const mod = (value: number, divisor: number) =>
  ((value % divisor) + divisor) % divisor;

const pulse = (frame: number, period: number, offset = 0) =>
  0.5 + 0.5 * Math.sin((mod(frame + offset, period) / period) * TAU);

const quadPoint = (a: Point, b: Point, c: Point, t: number): Point => {
  const u = 1 - t;
  return {
    x: u * u * a.x + 2 * u * t * b.x + t * t * c.x,
    y: u * u * a.y + 2 * u * t * b.y + t * t * c.y,
  };
};

