const WorldMap: React.FC<{frame: number}> = ({frame}) => {
  const mapScale = 1 + (0.5 - 0.5 * Math.cos((mod(frame, 900) / 900) * TAU)) * 0.006;
  const scanT = mod(frame, 900) / 900;
  const scanX = -260 + scanT * 2440;
  const scanOpacity = Math.sin(Math.PI * scanT) * 0.5;

  return (
    <svg
      width="1920"
      height="800"
      viewBox="0 130 1920 800"
      style={{position: 'absolute', left: 0, top: 118, overflow: 'visible'}}
    >
      <defs>
        <linearGradient id="clean-land-fill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0" stopColor={C.landHi} />
          <stop offset="1" stopColor={C.land} />
        </linearGradient>
        <linearGradient id="clean-scan" x1="0" y1="0" x2="1" y2="0">
          <stop offset="0" stopColor={C.cyan} stopOpacity="0" />
          <stop offset="0.48" stopColor={C.cyan} stopOpacity="0.02" />
          <stop offset="0.5" stopColor={C.cyan} stopOpacity="0.22" />
          <stop offset="0.52" stopColor={C.cyan} stopOpacity="0.02" />
          <stop offset="1" stopColor={C.cyan} stopOpacity="0" />
        </linearGradient>
        <filter id="packet-glow" x="-250%" y="-250%" width="600%" height="600%">
          <feGaussianBlur stdDeviation="3.4" result="b" />
          <feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
        <filter id="hotspot-glow" x="-160%" y="-160%" width="420%" height="420%">
          <feGaussianBlur stdDeviation="7" result="b" />
          <feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
        <clipPath id="clean-world-clip"><path d={MAP_SPHERE_D} /></clipPath>
        {routes.map((route) => (
          <linearGradient
            key={`gradient-${route.index}`}
            id={`route-gradient-${route.index}`}
            gradientUnits="userSpaceOnUse"
            x1={route.start.x}
            y1={route.start.y}
            x2={route.end.x}
            y2={route.end.y}
          >
            <stop offset="0" stopColor={C.coral} />
            <stop offset="0.58" stopColor={C.cyan} />
            <stop offset="1" stopColor={route.blocked ? C.mint : C.cyan} />
          </linearGradient>
        ))}
      </defs>

      <g transform={`translate(960 535) scale(${mapScale}) translate(-960 -535)`}>
        <path d={MAP_SPHERE_D} fill={C.ocean} fillOpacity="0.72" stroke="rgba(102,139,160,0.26)" strokeWidth="1.2" />
        <path d={MAP_GRATICULE_D} fill="none" stroke="rgba(102,139,160,0.09)" strokeWidth="0.7" />
        <path d={MAP_LAND_D} fill="url(#clean-land-fill)" stroke={C.coast} strokeOpacity="0.7" strokeWidth="1.05" />
        <path d={MAP_BORDERS_D} fill="none" stroke={C.border} strokeOpacity="0.7" strokeWidth="0.62" />

        <g clipPath="url(#clean-world-clip)" opacity={scanOpacity}>
          <rect x={scanX - 95} y="135" width="190" height="790" fill="url(#clean-scan)" />
          <line x1={scanX} y1="150" x2={scanX} y2="915" stroke={C.cyan} strokeOpacity="0.35" strokeWidth="1" />
        </g>

        {routes.map((route) => {
          const travel = mod(frame + route.index * 29, route.period) / route.period;
          const eased = Easing.inOut(Easing.cubic)(travel);
          const packet = quadPoint(route.start, route.control, route.end, eased);
          const activation = Math.pow(
            0.5 + 0.5 * Math.sin((frame / 300) * TAU + (route.index % 3) * (TAU / 3)),
            2.4,
          );
          const edgeFade = Math.pow(Math.sin(Math.PI * travel), 0.8);
          const packetOpacity = activation * edgeFade;
          const destinationPulse = Math.max(0, (travel - 0.72) / 0.28) * activation;
          const packetColor = route.blocked && travel > 0.72 ? C.mint : C.coral;

          return (
            <g key={`route-${route.index}`}>
              <path
                d={route.path}
                fill="none"
                stroke={`url(#route-gradient-${route.index})`}
                strokeWidth={1.1 + activation * 0.65}
                strokeOpacity={0.13 + activation * 0.43}
                strokeDasharray="3 8"
                strokeDashoffset={-frame * 0.32 - route.index * 4}
                strokeLinecap="round"
              />
              <circle
                cx={packet.x}
                cy={packet.y}
                r={2.7 + activation * 1.5}
                fill={packetColor}
                opacity={packetOpacity}
                filter="url(#packet-glow)"
              />
              {route.blocked ? (
                <g opacity={destinationPulse}>
                  <circle cx={route.end.x} cy={route.end.y} r={8 + destinationPulse * 8} fill="none" stroke={C.mint} strokeWidth="1.35" />
                  <path d={`M ${route.end.x - 4} ${route.end.y} L ${route.end.x - 1} ${route.end.y + 3} L ${route.end.x + 5} ${route.end.y - 5}`} fill="none" stroke={C.mint} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
                </g>
              ) : null}
            </g>
          );
        })}

        {geoNodes.slice(0, 8).map((node, index) => {
          const p = pulse(frame, [180, 225, 300][index % 3], node.phase);
          return (
            <g key={`hotspot-${node.id}`} opacity={0.28 + p * 0.25} filter="url(#hotspot-glow)">
              <circle cx={node.x} cy={node.y} r={12 + p * 9} fill={C.coral} fillOpacity="0.05" stroke={C.coral} strokeOpacity="0.25" strokeWidth="1" />
            </g>
          );
        })}

        {geoNodes.map((node, index) => {
          const p = pulse(frame, 225, node.phase);
          const color = node.tier === 'origin' ? C.coral : node.tier === 'relay' ? C.mint : C.cyan;
          return (
            <g key={node.id}>
              <circle cx={node.x} cy={node.y} r={6 + p * 1.8} fill={C.bgDeep} stroke={color} strokeOpacity="0.48" strokeWidth="1" />
              <circle cx={node.x} cy={node.y} r={2.3 + p * 0.7} fill={color} />
            </g>
          );
        })}
      </g>
    </svg>
  );
};

